INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Docker container isolation$q$, $q$Each game server runs in its own isolated Docker container for security and resource control.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Multi-game support$q$, $q$Supports Minecraft, Valheim, Palworld, Terraria, Enshrouded, Factorio and more via community eggs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$One-click server deployment$q$, $q$Provision and configure new game servers through a guided web UI without manual server setup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Real-time resource monitoring$q$, $q$Track CPU, memory and disk usage per server instance from the dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Built-in security controls$q$, $q$Native SSL, two-factor authentication and AES-256 encryption support are included.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Pterodactyl ecosystem compatibility$q$, $q$Works with many existing Pterodactyl eggs and migration paths for panels already running Pterodactyl.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Role-based access$q$, $q$Assign granular permissions so hosting businesses can safely give customers or staff limited server access.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Completely free and open source with no licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Faster release cadence and security patching than upstream Pterodactyl at the time of the fork$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Docker isolation keeps servers secure and resource-contained$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Broad multi-game support through a mature eggs ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Active community documentation and Discord support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Requires users to provide and manage their own server or VPS infrastructure$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$No official commercial support or SLA since it is volunteer-maintained$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Newer project than Pterodactyl, so the long-term roadmap depends on continued volunteer involvement$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Self-hosting requires Docker and Linux systems administration knowledge$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$AGPLv3 licensing imposes stricter copyleft obligations on anyone redistributing modified versions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$What is Pelican Panel?$q$, $q$Pelican Panel is a free, open-source web-based control panel for deploying, configuring and monitoring game servers, with each server running in an isolated Docker container.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Is Pelican Panel free?$q$, $q$Yes. Pelican Panel is entirely free and open source under the AGPLv3 license; users only pay for their own server hardware or hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$How is Pelican Panel related to Pterodactyl?$q$, $q$Pelican is a community fork of Pterodactyl, created in mid-2024 after Pterodactyl's Wings component went an extended period without updates, aiming to ship faster releases and security fixes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$What games does Pelican Panel support?$q$, $q$Pelican supports Minecraft, Valheim, Palworld, Terraria, Enshrouded, Factorio and many other games through community-built server templates called eggs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Do I need Docker to run Pelican Panel?$q$, $q$Yes, Pelican relies on Docker containers, managed through its Wings agent, to isolate and run each game server instance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Can I migrate from Pterodactyl to Pelican Panel?$q$, $q$Pelican maintains compatibility with much of the Pterodactyl ecosystem, including many eggs, and the community provides migration documentation for existing Pterodactyl installations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Who maintains Pelican Panel?$q$, $q$Pelican Panel is maintained by a volunteer open-source community through the pelican-dev GitHub organization, with no single company behind it.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$What license does Pelican Panel use?$q$, $q$Pelican Panel is licensed under the GNU Affero General Public License v3 (AGPLv3), which requires that modifications used to provide a network service also be made available under the same license.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Game hosting businesses$q$, $q$Hosting companies use Pelican to give paying customers self-service control panels for their own isolated Minecraft, Valheim or Rust servers.$q$, $q$Commercial game server hosts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Gaming communities and clans$q$, $q$Communities self-host Pelican to run and manage their own dedicated servers for multiplayer games without recurring hosting fees.$q$, $q$Gaming communities and clan admins$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Homelab and hobbyist self-hosting$q$, $q$Hobbyists running home servers or VPS instances use Pelican to manage multiple game servers from a single secure dashboard.$q$, $q$Self-hosters and homelab enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited self-hosted servers","Docker container isolation","Full access to source code","Community Discord and documentation support","No license fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pelican Panel is a free, open-source control panel for managing game servers. It gives hosting operators and gaming communities a browser-based dashboard for creating, configuring, starting, stopping and monitoring servers, while the underlying game processes run in isolated Docker containers managed by a companion agent called Wings.$q$, $q$The project began in mid-2024 as a fork of Pterodactyl, one of the most widely used open-source game panels, after community maintainers grew concerned about a long gap in Pterodactyl's Wings releases. Pelican was built to keep the familiar workflow and much of the existing ecosystem (including server templates known as eggs) while shipping updates and security fixes faster.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every server managed by Pelican runs in its own Docker container, which isolates dependencies, enforces resource limits, and prevents one server from affecting another on the same host. The panel supports a wide range of games out of the box, including Minecraft, Terraria, Palworld, Valheim, Enshrouded and Factorio, with more added through community-maintained eggs.$q$, $q$Security features include native SSL support, two-factor authentication and AES-256 encryption, and the interface offers one-click installations, real-time resource monitoring and role-based access for teams managing multiple servers or customers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pelican Panel is 100% free and open source under the AGPLv3 license, with no paid tiers, license fees or usage limits imposed by the project itself.$q$, $q$The only costs users incur are for the server hardware or VPS they choose to run it on, which is the same model used by comparable panels like Pterodactyl and Crafty Controller.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('55f67bf7-283b-46a3-a504-fefc5445313f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Built-in UI stencils$q$, $q$Ready-made shape libraries for desktop, web and mobile interface elements speed up wireframing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Multi-page documents$q$, $q$Organize mockups across multiple linked pages within a single project file.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Basic interactive prototyping$q$, $q$Link pages together to simulate simple click-through navigation flows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Diagramming shapes$q$, $q$General-purpose shapes support flowcharts and simple diagrams alongside UI mockups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Cross-platform desktop app$q$, $q$Runs natively on Windows, macOS and Linux via Electron.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Zip-based file format$q$, $q$Version 3's file format improves performance and memory use for large documents with embedded images.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Importable stencil collections$q$, $q$Extend the default shape set by importing external or OpenClipArt-based stencil packs.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Completely free with no subscription or account required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Works fully offline as a native desktop application$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Simple, low-fidelity sketch style is fast for early-stage wireframing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Open source under GPL, so the code can be inspected or modified$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Lightweight compared to full cloud design suites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$No real-time multiplayer collaboration found in modern tools like Figma or Penpot$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Development pace has historically been slow, with long gaps between releases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Lacks design tokens, component variants and advanced prototyping interactions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Interface and stencil library feel dated compared with current design tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$No official cloud sync, version history or team management features$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Is Pencil Project free to use?$q$, $q$Yes, Pencil Project is completely free and open source under the GNU GPL v2 or later license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$What platforms does Pencil Project support?$q$, $q$Pencil Project runs on Windows, macOS and Linux as a native desktop application built on Electron.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Who develops Pencil Project?$q$, $q$Pencil Project is developed by Evolus, a software company based in Ho Chi Minh City, Vietnam.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Can Pencil Project create interactive prototypes?$q$, $q$Pencil supports basic interactive prototyping by linking pages together to simulate simple navigation flows, though it lacks the advanced interaction features of modern prototyping tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$How is Pencil Project different from Figma or Penpot?$q$, $q$Pencil is an offline desktop app with a simpler, low-fidelity sketching toolset, while Figma and Penpot are cloud-based platforms with real-time collaboration, component systems and richer prototyping.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$What file format does Pencil Project use?$q$, $q$Since version 3, Pencil uses a zip-based file format designed to better handle large documents and embedded bitmap assets.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Is Pencil Project still maintained?$q$, $q$The most recent stable release, version 3.1.1, shipped in January 2023; the project has had periods of slower development but remains available as open-source software.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Can I extend Pencil Project with custom shapes?$q$, $q$Yes, users can import additional stencil collections, including OpenClipArt-based shape libraries, to extend the default toolset.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Early-stage wireframing$q$, $q$Designers and developers use Pencil to quickly rough out screen layouts before moving to higher-fidelity tools.$q$, $q$UI/UX designers and developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Student and academic projects$q$, $q$Students use Pencil's free, offline tool to create UI mockups and diagrams for coursework without needing paid software.$q$, $q$Students and educators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Lightweight diagramming$q$, $q$Small teams use Pencil's general shape libraries to sketch flowcharts and simple process diagrams.$q$, $q$Small teams and hobbyist developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full desktop application for Windows, macOS and Linux","Built-in UI and diagramming stencils","Multi-page documents","Basic interactive prototyping","GPL-licensed source code"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pencil Project is a free, open-source desktop application for sketching GUI mockups, wireframes and simple diagrams. Built by Evolus, a software company based in Ho Chi Minh City, Vietnam, it began life in 2008 as a Firefox-based sketching tool before becoming a standalone Electron desktop app in its version 3 rewrite.$q$, $q$The tool is aimed at anyone who needs to quickly rough out an interface or flow, from students and hobbyists to small development teams, without paying for software or creating an online account. It runs on Windows, macOS and Linux.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pencil ships with built-in shape and UI-control stencils covering desktop, web and mobile interface elements, plus general diagramming shapes for flowcharts and basic diagrams. Users can build multi-page documents and link pages together to create simple clickable prototypes.$q$, $q$The version 3 file format is zip-based, which improves handling of large documents and embedded bitmap assets compared with the original XML-based format, and the app supports importing additional stencil collections, including OpenClipArt-based shape libraries, to extend its default toolset.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('00563610-94ad-4982-9919-0d497b31162d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pencil Project is completely free and released under the GNU General Public License v2 or later, with no paid tiers, subscriptions or enterprise licensing offered by Evolus.$q$, $q$Because there is no commercial edition, all users get the same feature set regardless of use case, and the software can be freely redistributed or modified under the terms of the GPL.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('00563610-94ad-4982-9919-0d497b31162d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$No-code product analytics$q$, $q$Auto-capture user interactions and build funnels, trends and retention reports without writing tracking code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$In-app guides and walkthroughs$q$, $q$Create onboarding flows, feature announcements and tooltips that appear directly inside the product.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Session replay$q$, $q$Watch recorded user sessions to see exactly how customers navigate and where they get stuck.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$In-app surveys and NPS$q$, $q$Collect sentiment, satisfaction and feedback data from users while they are active in the product.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Guide orchestration$q$, $q$Coordinate multi-step, targeted in-app campaigns across user segments on higher-tier plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Roadmapping$q$, $q$Share product roadmaps and collect feature requests directly tied to usage data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Pendo AI and Novus$q$, $q$AI-driven proactive insights, recommendations and auto-generated content built on top of product usage data.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$No-code instrumentation makes it accessible to product managers without engineering support$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Combines analytics, in-app guidance and feedback in a single connected platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Generous free tier supports up to 500 monthly active users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Widely adopted by large enterprises with strong customer references$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Growing AI feature set aimed at surfacing proactive product insights$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Paid plans are not publicly priced and can be expensive for smaller companies$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Enterprise contracts require annual commitments and sales negotiation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Some advanced features like session replay and orchestration are gated behind higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Can require significant configuration effort to get full value from analytics and guides$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Free plan branding (Pendo-branded roadmaps and NPS surveys) limits white-labeling for smaller teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$What is Pendo used for?$q$, $q$Pendo is used by software companies to track product usage, guide users with in-app messages and walkthroughs, collect feedback, and prioritize roadmap decisions based on real usage data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Does Pendo have a free plan?$q$, $q$Yes, Pendo Free is free forever for up to 500 monthly active users and includes product analytics, in-app guides, and Pendo-branded roadmaps and NPS surveys.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$How much does Pendo cost?$q$, $q$Pendo's paid Base, Core and Ultimate plans are not publicly priced; they scale with monthly active users and require a custom quote from Pendo's sales team.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Who founded Pendo and when?$q$, $q$Pendo was founded in 2013 and is headquartered in Raleigh, North Carolina.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$What is the difference between Pendo Core and Ultimate?$q$, $q$Core adds session replay on top of base analytics and guides, while Ultimate adds sentiment surveys, guide orchestration and data sync for more advanced use cases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$What are the main alternatives to Pendo?$q$, $q$Common alternatives include Amplitude, Mixpanel, Heap, WalkMe and Gainsight, depending on whether a team prioritizes analytics, digital adoption or customer success.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Does Pendo require coding to set up?$q$, $q$No, Pendo uses a no-code auto-capture approach so product teams can build analytics reports and in-app guides without writing custom tracking code.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$What is Pendo Novus?$q$, $q$Novus is Pendo's AI-native product monitoring offering, currently in open beta, that provides proactive recommendations and automation such as AI-generated guide content.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Product-led onboarding$q$, $q$SaaS teams use Pendo's in-app guides to onboard new users and drive adoption of key features without manual outreach.$q$, $q$Product managers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Feature adoption analytics$q$, $q$Product teams track which features are used, ignored or abandoned to prioritize the roadmap based on real usage data.$q$, $q$Product and UX teams at SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$In-app customer feedback$q$, $q$Customer success and product teams collect NPS scores and sentiment surveys directly inside the application to reduce churn.$q$, $q$Customer success and product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Free$q$, $q$Free$q$, $q$Forever$q$, NULL, $q$["Up to 500 monthly active users","Product analytics","In-app guides","Pendo-branded roadmaps","Pendo-branded NPS surveys"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Base$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Product analytics","In-app guides","Custom monthly active user volume"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Core$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Everything in Base","Session replay","Most popular tier"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$Ultimate$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Everything in Core","Sentiment surveys","Guide orchestration","Data sync"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pendo is a product experience management platform used by software companies to track how customers use their product, guide them through onboarding and new features with in-app messages, and collect structured feedback. Founded in 2013 and based in Raleigh, North Carolina, Pendo has grown from a product-analytics startup into a broader suite spanning analytics, guides, session replay, surveys, roadmapping and AI-driven insights.$q$, $q$The platform is built around a no-code instrumentation model: after installing a lightweight snippet, product and growth teams can build reports, funnels, guides and segments without needing engineers to add tracking code for every new event.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pendo's core modules include product analytics (usage trends, funnels, retention and feature adoption), in-app guides and walkthroughs for onboarding and feature announcements, session replay for watching real user sessions, and in-app surveys including NPS and sentiment collection.$q$, $q$Higher tiers add orchestration for coordinating multi-step guide campaigns, data sync to push product usage data into a data warehouse or CRM, and AI-native capabilities under Pendo AI and the Novus beta, which surface proactive recommendations and can auto-generate elements like guide copy or usage summaries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b9a45dfc-a1c5-48e9-bcd3-8ece140c07de', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pendo Free is available forever for up to 500 monthly active users and includes core product analytics, in-app guides, and Pendo-branded roadmaps and NPS surveys with no credit card required.$q$, $q$Paid plans, Base, Core and Ultimate, are not publicly priced and scale with monthly active user volume; Core adds session replay and is marketed as the most popular tier, while Ultimate adds sentiment surveys, orchestration and data sync. All paid tiers require contacting Pendo's sales team for a custom quote.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Legally binding e-signatures$q$, $q$Multi-party digital signing workflows with a complete, verifiable audit trail.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Document validation$q$, $q$Validator allows recipients to independently confirm a signed document's authenticity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$KYC and AML compliance$q$, $q$Penneo KYC screens and verifies client identities to support anti-money-laundering obligations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Open API and integrations$q$, $q$Out-of-the-box integrations with accounting and practice-management software plus an open API for custom workflows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Nordic regulatory focus$q$, $q$Built around the compliance needs of Danish, Swedish and Norwegian auditors, accountants and financial firms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Multi-language support$q$, $q$Interfaces and signing flows available in English, Danish, Swedish and Norwegian.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Deep specialization in regulated, document-heavy Nordic industries like auditing and finance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Combines e-signing with KYC and identity verification in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Open API and integrations with accounting and practice-management tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Strong reputation and long track record with more than 3,000 business customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Now backed by Visma's scale and Nordic business software ecosystem$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Pricing is not public and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Primarily optimized for Nordic markets and languages compared with global e-signature giants$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$No longer an independent public company, which may affect product roadmap autonomy going forward$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Smaller global brand recognition than DocuSign or Adobe Acrobat Sign outside the Nordics$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Feature depth outside signing and KYC (e.g., broader contract lifecycle management) is more limited than some larger suites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$What is Penneo used for?$q$, $q$Penneo is used for digital document signing, document verification and KYC/AML compliance, primarily by auditors, accountants, law firms and financial institutions in the Nordic region.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Is Penneo still a public company?$q$, $q$No. Penneo was listed on the Nasdaq First North Growth Market Denmark from 2020 until it was acquired by Visma through a tender offer completed in early 2025, after which it was delisted and became a Visma subsidiary.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Who owns Penneo now?$q$, $q$Penneo is now wholly owned by Visma, a large Nordic enterprise software group, following a 2024-2025 acquisition.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$When was Penneo founded?$q$, $q$Penneo was founded in 2014 in Copenhagen, Denmark by six Danish entrepreneurs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Does Penneo offer KYC and identity verification?$q$, $q$Yes, Penneo KYC provides identity verification and anti-money-laundering screening, expanded through Penneo's 2020 acquisition of KYC software from CLA Reply.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$How much does Penneo cost?$q$, $q$Penneo does not publish pricing publicly; costs depend on document volume, user count and which modules are needed, and require contacting sales for a quote.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$What are the main alternatives to Penneo?$q$, $q$Common alternatives include DocuSign, Adobe Acrobat Sign, Signicat and Scrive.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$What industries use Penneo most?$q$, $q$Penneo is most widely used in audit and accounting, banking and finance, legal services, real estate, and administration and HR.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Audit and accounting document signing$q$, $q$Auditors and accounting firms use Penneo to collect legally binding signatures on financial statements, engagement letters and client documents.$q$, $q$Audit and accounting firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Financial services KYC compliance$q$, $q$Banks and financial institutions use Penneo KYC to verify client identities and meet anti-money-laundering obligations alongside signed agreements.$q$, $q$Banks and financial services compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Legal and real estate contract signing$q$, $q$Law firms and real estate businesses use Penneo Sign to execute contracts and agreements with a verifiable audit trail.$q$, $q$Legal and real estate professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$Custom$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Digital signing workflows","Document validation","Optional KYC/AML module","Open API and integrations","Volume-based pricing by document and user count"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Penneo is a Copenhagen-based digital signature and compliance platform founded in 2014 to simplify document signing for professional services firms. Its products, Penneo Sign, Validator and Penneo KYC, combine legally binding e-signatures with document verification and know-your-customer checks aimed at auditors, accountants, banks and law firms.$q$, $q$Penneo was publicly traded on the Nasdaq First North Growth Market Denmark from 2020 until it was acquired by Visma, the Nordic enterprise software group, through a tender offer completed in early 2025, after which it was delisted and became a wholly owned Visma subsidiary.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Penneo Sign provides legally binding electronic signatures with a full audit trail, multi-party signing workflows and an open API for embedding signing into other business applications. Validator lets recipients independently verify the authenticity of signed documents.$q$, $q$Penneo KYC, expanded through the 2020 acquisition of CLA Reply's KYC software, adds identity verification and anti-money-laundering screening, which is particularly relevant for regulated industries like auditing, banking and real estate that must document client due diligence alongside signed agreements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d258a01-ef39-4b35-84fd-1f22985df12e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Penneo does not publish list pricing; prospective customers request a quote based on document volume, the number of users, and which modules (Sign, Validator, KYC) are needed.$q$, $q$Pricing is typically structured for business and enterprise customers such as audit firms, accounting practices and financial institutions rather than individual consumers, reflecting its focus on regulated, high-volume document workflows.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Open-source and self-hostable$q$, $q$Full source code available under MPL 2.0, with the option to self-host instead of using Penpot's cloud.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Real-time multiplayer editing$q$, $q$Multiple designers can edit the same file simultaneously with live cursors and comments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$SVG-native file format$q$, $q$Designs are stored using standard SVG, keeping files interoperable with web technologies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Interactive prototyping$q$, $q$Build clickable prototypes with flows, interactions and transitions between screens.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Design systems and components$q$, $q$Create reusable components, libraries and shared design tokens across projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Design-to-code handoff$q$, $q$Developers can inspect designs and export code-ready specs and assets directly from the file.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Plugin ecosystem and API$q$, $q$Extend Penpot with plugins and integrate it into other tools via a REST API.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Genuinely open source under MPL 2.0, unlike most competing design tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Free tier is usable for small teams with unlimited design files$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Self-hosting option gives organizations full control over design data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$SVG-native format keeps designs closer to open web standards$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Backed by venture funding while maintaining its open-source commitment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Smaller plugin and template ecosystem than Figma's mature marketplace$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Self-hosted Private Server plan is expensive and aimed at large enterprises$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Some advanced features and performance still lag behind Figma for very large, complex files$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Kaleidos is a small company relative to Figma/Adobe, which may affect long-term feature velocity$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Free plan is capped at eight team members, limiting it for larger teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Is Penpot free to use?$q$, $q$Yes, Penpot offers a free Professional cloud plan for up to eight team members with unlimited design files, plus paid Unlimited and Enterprise tiers and a self-hosted option since the software itself is open source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Who builds Penpot?$q$, $q$Penpot is built by Kaleidos, a Madrid, Spain-based technology company founded in 2011 that pivoted from consulting to open-source product development to create Penpot.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Is Penpot open source?$q$, $q$Yes, Penpot's full codebase is open source under the Mozilla Public License 2.0, and it can be self-hosted on a company's own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Can Penpot be self-hosted?$q$, $q$Yes, in addition to Penpot's hosted cloud service, organizations can self-host Penpot on their own servers, including via a paid Private Server enterprise offering.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$How is Penpot different from Figma?$q$, $q$Penpot is fully open source and self-hostable with an SVG-native file format, while Figma is a proprietary, closed-source cloud platform; Penpot was built specifically as an open alternative to Figma.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$When did Penpot launch?$q$, $q$Penpot's first alpha version launched on February 2, 2021, and was unveiled publicly at the FOSDEM open-source conference.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$How much does Penpot's Unlimited plan cost?$q$, $q$The Unlimited cloud plan costs $7 per user per month, with the total bill capped at $175 per month regardless of team size.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Who are Penpot's main competitors?$q$, $q$Penpot's main competitors are Figma, Sketch and Adobe XD, along with other prototyping and design tools such as Pencil Project.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Open-source design workflow$q$, $q$Design and product teams that want to avoid proprietary lock-in use Penpot for UI design, prototyping and design systems.$q$, $q$Product design and UX teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Self-hosted enterprise design$q$, $q$Enterprises and government agencies with strict data governance requirements self-host Penpot to keep design data on their own infrastructure.$q$, $q$Enterprises and public-sector organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Design-to-development handoff$q$, $q$Developers use Penpot's code inspection and SVG-based files to translate designs into production code more directly.$q$, $q$Frontend developers and design engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Professional$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 8 team members plus unlimited viewers","10GB storage","7-day version history and file recovery","Unlimited design files"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Unlimited$q$, $q$$7/user/month (capped at $175/month)$q$, $q$Monthly$q$, NULL, $q$["25GB storage","30-day version history and file recovery","Early access to upcoming features","50% event discount"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Enterprise$q$, $q$From $950/month ($25/user/month)$q$, $q$Monthly$q$, NULL, $q$["Unlimited storage","90-day version history and file recovery","Centralized admin console","Advanced team permissions and SSO","Audit logs and plugin allowlist"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$Private Server (self-hosted)$q$, $q$$50,000/year$q$, $q$Annual$q$, NULL, $q$["Dedicated private infrastructure","Enterprise SSO and access controls","SCIM role assignment","Guest access controls","Choice of hosting region"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Penpot is an open-source, web-based platform for UI design, prototyping and design systems, built by the Madrid-based company Kaleidos. It launched its first alpha in February 2021 and was designed from the start as an open alternative to closed-source tools like Figma, Sketch and Adobe XD, with a codebase released under the Mozilla Public License 2.0.$q$, $q$Because Penpot is open source, it can be used as a hosted cloud product at penpot.app or self-hosted on a company's own servers, giving organizations control over their design data and infrastructure while still supporting real-time multiplayer editing and collaboration.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Penpot supports multiplayer real-time editing, commenting, interactive prototyping, and reusable design system components and libraries, with files stored in an SVG-native format that keeps designs closer to standard web markup than proprietary binary formats.$q$, $q$For developers, Penpot provides code inspection and design-to-code handoff features, a plugin system for extending functionality, and a REST API, while enterprise-focused plans add single sign-on, centralized admin consoles, audit logs and plugin allowlisting for governance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Penpot's cloud Professional plan is free for up to eight team members with unlimited viewers, 10GB of storage and 7-day version history. The Unlimited plan costs $7 per user per month, capped at $175 per month regardless of team size, and adds 25GB of storage and 30-day version history.$q$, $q$The Enterprise cloud plan starts around $950 per month ($25 per user per month) and adds unlimited storage, 90-day version history, SSO and admin controls, while organizations needing a fully private deployment can purchase a self-hosted Private Server plan priced around $50,000 per year.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e79526e3-fc9f-4ec0-848a-0c70b7a3bd92', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Automated visual regression testing$q$, $q$Captures and compares UI screenshots to automatically flag unintended visual changes.$q$, 0);
