INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Visual review workflow$q$, $q$Team members approve or reject detected visual diffs directly within pull requests.$q$, 3);
