INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$BrowserStack infrastructure$q$, $q$Leverages BrowserStack's real browser and device grid for more accurate visual comparisons.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Generous free tier with 5,000 screenshots per month and unlimited users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Strong integrations with popular testing frameworks and CI pipelines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Backed by BrowserStack's infrastructure and broader testing ecosystem$q$, 2);
