INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Best value requires already being invested in BrowserStack's broader testing ecosystem$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$What is Percy used for?$q$, $q$Percy is used for automated visual regression testing, capturing screenshots of a web application's UI and flagging unintended visual changes before code is merged.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Who owns Percy?$q$, $q$Percy was originally built by Perceptual Inc., founded in San Francisco in 2015, and has been owned by BrowserStack since BrowserStack acquired it in July 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Is Percy free?$q$, $q$Percy offers a free plan with 5,000 screenshots per month and unlimited users and projects, with paid Professional and Enterprise plans for higher screenshot volumes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$How much does Percy's Professional plan cost?$q$, $q$Percy's Professional plan is priced around $149 per month when billed annually (or roughly $199 billed monthly) and includes about 25,000 screenshots per month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$What testing tools does Percy integrate with?$q$, $q$Percy integrates with popular testing frameworks and CI/CD tools including Cypress, Playwright, Selenium and Storybook.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$What is the difference between Percy and Chromatic?$q$, $q$Percy is a general-purpose visual testing platform integrated with BrowserStack's infrastructure, while Chromatic is built specifically around Storybook by Storybook's own maintainers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Does Percy support cross-browser testing?$q$, $q$Yes, Percy supports cross-browser and responsive visual testing, capturing screenshots across multiple browsers and viewport sizes.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$What are Percy's main competitors?$q$, $q$Percy's main competitors include Chromatic, Applitools and BackstopJS.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Automated UI regression testing$q$, $q$Frontend teams integrate Percy into CI pipelines to automatically catch unintended visual changes before merging code.$q$, $q$Frontend engineers and QA teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Design system quality assurance$q$, $q$Design systems teams use Percy to ensure shared component libraries render consistently across browsers and updates.$q$, $q$Design systems and component library teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Cross-browser visual validation$q$, $q$QA teams use Percy to verify layouts render correctly across different browsers and screen sizes before release.$q$, $q$QA engineers and release managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Free$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["5,000 screenshots per month","Unlimited users","Unlimited projects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Professional$q$, $q$$149/month (annual) or $199/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["25,000 screenshots per month","1 year build history","Team collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Custom SLAs","SOC 2/ISO compliance documentation","Dedicated support","Unlimited device access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Percy is a visual review and visual regression testing platform that captures screenshots of an application's UI during automated test runs and compares them against an approved baseline to catch unintended visual changes. It was originally built by Perceptual Inc., founded in San Francisco in 2015, and has been owned and operated by BrowserStack since its acquisition in July 2020.$q$, $q$Rather than relying on developers or QA testers to manually eyeball UI changes across browsers and screen sizes, Percy automates the comparison and surfaces only meaningful visual diffs for a human to review and approve, integrating directly into CI/CD pipelines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Percy supports cross-browser and responsive visual testing, capturing screenshots across multiple browsers and viewport sizes to catch layout issues specific to certain devices or resolutions. It integrates with popular frameworks and CI tools including Cypress, Playwright, Selenium and Storybook.$q$, $q$The platform provides a visual review workflow where teams approve or reject detected diffs directly in pull requests, along with build history, team collaboration features, and, as part of BrowserStack, access to real browser and device infrastructure for more accurate rendering.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0521ec36-4a18-4308-8b35-efe654ddfaa1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Percy's Free plan includes 5,000 screenshots per month with unlimited users and projects, making it accessible for small teams or side projects to start visual testing at no cost.$q$, $q$The Professional plan, priced around $149 per month billed annually (or $199 billed monthly), includes about 25,000 screenshots per month and a year of build history, while the Enterprise plan offers custom pricing with SLAs, compliance documentation and dedicated support for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Automated commission calculation$q$, $q$Replaces manual spreadsheets with a rules-based engine for calculating sales commissions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Complex plan modeling$q$, $q$Supports tiered, multi-variable compensation plans, quotas and territory rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Rep self-service dashboards$q$, $q$Sales reps can view their own earnings and performance in real time, reducing disputes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Analytics Studio$q$, $q$Reporting on commission spend, plan performance and rep behavior for finance and RevOps leaders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Audit trail and compliance$q$, $q$Maintains a verifiable calculation history to support finance audits and compensation disputes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$CRM and ERP integrations$q$, $q$Connects to existing sales and finance systems to pull data needed for commission calculations.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Automates error-prone manual commission calculations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Handles complex, multi-tier compensation plans and territory rules$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Rep self-service dashboards improve transparency and reduce disputes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Backed by significant growth funding ($75M led by JMI Equity)$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Established track record since 2006 with customers across many industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Pricing is not public and requires a sales process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Smaller company scale (around 137 employees) compared to larger SPM competitors like Xactly or SAP$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Implementation of complex compensation plans can require significant configuration time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Primarily suited to mid-market and enterprise teams rather than small sales teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Global headquarters location has shifted over time, which may affect regional support consistency$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$What is Performio used for?$q$, $q$Performio is used to automate the calculation, management and communication of sales commissions and incentive compensation for sales, finance and revenue operations teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$When was Performio founded?$q$, $q$Performio was founded in 2006 by sales-compensation expert David Marshall in South Melbourne, Australia.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Where is Performio headquartered?$q$, $q$Performio originated in South Melbourne, Australia, and established a global headquarters in the United States, with more recent operations centered in Southern California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$How much does Performio cost?$q$, $q$Performio does not publish pricing; cost depends on the number of payees, plan complexity and integrations, and requires a custom quote from sales.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$What is Performio's Analytics Studio?$q$, $q$Analytics Studio is Performio's reporting module for analyzing commission spend, incentive plan performance and sales rep behavior.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$How much funding has Performio raised?$q$, $q$Performio has raised $75 million in growth investment led by JMI Equity, with additional backing from Flow Capital.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Who are Performio's main competitors?$q$, $q$Performio competes with Xactly, CaptivateIQ, Varicent and SAP Commissions in the sales performance management and incentive compensation category.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$What industries use Performio?$q$, $q$Performio serves manufacturing, MedTech, transportation and logistics, banking, insurance, distribution, media and advertising, SaaS and telecom companies.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Sales commission automation$q$, $q$Sales operations teams replace spreadsheet-based commission tracking with Performio's automated calculation engine.$q$, $q$Sales operations and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Complex incentive plan management$q$, $q$Organizations with multi-tier, quota-based compensation plans use Performio to model and enforce plan rules accurately.$q$, $q$RevOps leaders and compensation analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Sales rep transparency$q$, $q$Sales reps use self-service dashboards to track their own commission earnings in real time, reducing disputes with finance.$q$, $q$Sales representatives and managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$Custom$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Automated commission calculation","Complex compensation plan modeling","Rep self-service dashboards","Analytics Studio reporting","CRM and ERP integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Performio is a cloud-based sales performance management and incentive compensation platform founded in 2006 by David Marshall in South Melbourne, Australia. The company expanded internationally, opening a U.S. headquarters in Irvine, California in 2017, and today serves customers globally from offices in both Australia and the United States.$q$, $q$The platform is built to replace manual, spreadsheet-based commission calculation with an automated, auditable engine capable of modeling complex compensation plans, quotas and territories for sales and revenue teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Performio's core Incentive Compensation engine automates commission calculations, handles complex plan rules, and gives reps visibility into their own earnings and performance through self-service dashboards, reducing disputes and manual reconciliation work for finance teams.$q$, $q$Its Analytics Studio provides reporting on commission spend, plan effectiveness and sales behavior, helping revenue operations and finance leaders understand whether incentive plans are actually driving the sales outcomes they were designed for.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bac928b-8b56-4410-b495-f9ee3e28df6b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Performio does not publish pricing on its website; as with most enterprise incentive compensation software, cost depends on the number of payees, the complexity of compensation plans, and any required integrations with CRM, ERP or payroll systems.$q$, $q$Prospective customers must contact Performio's sales team for a custom quote, and implementations are typically sold to mid-market and enterprise organizations rather than through self-serve signup.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Discounts and perks marketplace$q$, $q$Access to more than 9,000 discounts across retail, leisure, wellness and lifestyle brands.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Wellbeing support$q$, $q$Access to private and public medical and mental health resources for employees.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Peer and manager recognition$q$, $q$Tools for awarding monetary or gift-based incentives tied to performance and company values.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Global benefits coverage$q$, $q$Supports businesses operating across more than 30 countries with localized perks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Employee engagement analytics$q$, $q$Reporting on platform usage and engagement to help HR teams measure program impact.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Single unified portal$q$, $q$Combines perks, wellbeing and recognition in one login rather than multiple point solutions.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Consolidates perks, wellbeing and recognition into a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Large discounts marketplace with over 9,000 offers from recognizable brands$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Established provider with over a decade in the UK employee benefits market$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Supports international employers across more than 30 countries$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Recognition tools help reinforce company culture alongside tangible discounts$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Pricing is not public and requires a custom quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Some users report costs run higher than sourcing comparable perks individually$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Discount catalog and localization may feel more UK/Europe-centric for global teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Employee engagement with the platform can vary and requires ongoing internal promotion$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Bundled pricing means paying for modules an organization may not fully use$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$What is Perkbox used for?$q$, $q$Perkbox is used by employers to give staff access to discounts, wellbeing resources and peer or manager recognition tools through a single benefits platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$When was Perkbox founded?$q$, $q$Perkbox was founded in 2010 in London, originally under the name HuddleBuy, before rebranding to Perkbox.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$How much does Perkbox cost?$q$, $q$Perkbox does not publish pricing; it is sold on a custom, per-employee subscription basis that varies by company size, modules selected and contract length.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$How many discounts does Perkbox offer?$q$, $q$Perkbox gives employees access to more than 9,000 discounts and perks from retail, leisure, wellness and lifestyle brands.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Does Perkbox support international companies?$q$, $q$Yes, Perkbox serves businesses operating across more than 30 countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$What is Perkbox's relationship to HuddleBuy?$q$, $q$Perkbox was originally launched under the name HuddleBuy before rebranding to its current name and perks-focused positioning.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Who are Perkbox's main competitors?$q$, $q$Perkbox competes with other UK employee engagement and benefits platforms such as Reward Gateway and Benefex.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Does Perkbox include wellbeing benefits?$q$, $q$Yes, Perkbox includes wellbeing support such as access to private and public medical and mental health resources alongside its discounts and recognition tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Employee discounts and perks program$q$, $q$HR teams roll out Perkbox to give staff ongoing access to discounts across everyday retail, leisure and wellness brands.$q$, $q$HR and people teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Peer-to-peer recognition$q$, $q$Managers and employees use Perkbox's recognition tools to award monetary or gift-based incentives tied to performance and values.$q$, $q$Managers and employee engagement leads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Workplace wellbeing support$q$, $q$Employers use Perkbox's wellbeing resources to give staff access to medical and mental health support as part of a broader benefits package.$q$, $q$HR and wellbeing program managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$Custom$q$, $q$Custom (contact sales)$q$, $q$Annual$q$, NULL, $q$["Discounts and perks marketplace access","Wellbeing resources","Recognition and rewards tools","Engagement analytics and reporting","Per-employee pricing based on company size"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Perkbox is a London-based employee benefits, rewards and recognition platform founded in 2010, originally under the name HuddleBuy before rebranding around its current perks-focused positioning. It gives employers a single portal combining a discounts marketplace, wellbeing resources and peer and manager recognition tools.$q$, $q$The company serves more than 5,000 businesses across over 30 countries, with hundreds of thousands of employees using the platform regularly, and employs roughly 280 people.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Perkbox's discounts and perks marketplace gives employees access to more than 9,000 offers across retail, leisure, wellness and lifestyle brands, letting employers offer meaningful savings without negotiating individual vendor deals themselves.$q$, $q$Beyond discounts, the platform includes wellbeing support such as access to private and public medical or mental health resources, along with recognition tools that let managers and peers award monetary or gift-based incentives tied to performance and company values.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('42ee2d70-9cde-4237-84bd-e916bc055119', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Perkbox does not publish list pricing on its website; cost is quoted per employee based on company size, the modules selected (perks, wellbeing, recognition) and contract length.$q$, $q$Because pricing is bundled and custom, some smaller organizations report that assembling comparable perks individually through separate providers can be cheaper, while larger employers often value the administrative simplicity of a single consolidated platform.$q$]::text[], 2);
