-- Enrichment marathon batch: Pelican Panel, Pencil Project, Pendo, Penneo, Penpot, Percy, Performio, Perkbox

-- ── Pelican Panel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pelican Panel is a free, open-source game server management panel that lets hosts and communities deploy, configure and monitor Docker-isolated game servers through a modern web UI.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (volunteer-run open-source project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source community)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pelican Panel Review 2026: Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pelican Panel is a free open-source game server control panel and Pterodactyl successor. See features, Docker isolation, security and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pelican Panel is a free, open-source game server management panel used by hosting companies, gaming communities and self-hosters to deploy, configure and monitor game servers such as Minecraft, Valheim, Palworld, Terraria, Enshrouded and Factorio through a browser-based dashboard. It emerged in mid-2024 as a community-driven fork of Pterodactyl, the long-standing open-source panel whose Wings daemon had gone roughly 20 months without a release; volunteer maintainers created Pelican to restore a faster release cadence and continued security patching while staying architecturally close to the existing Pterodactyl ecosystem, including compatibility with many existing server installation templates known as eggs. Pelican Panel is released under the GNU Affero General Public License v3 (AGPLv3), a stricter copyleft license than Pterodactyl's original MIT license, chosen specifically to keep improvements to hosted deployments open to the community. Its core technical differentiator is Docker-based isolation: every game server instance runs in its own container, giving operators resource limits, native SSL support, two-factor authentication and AES-256 encryption support without bloating host machines with per-game dependencies. Because it is entirely free and community-maintained rather than sold as a commercial product, Pelican has no parent company, no funding rounds and no formal corporate headquarters; contributions and governance happen publicly through GitHub and Discord. It targets a specific niche: gaming communities, small and mid-size game-hosting businesses, and hobbyists who want the convenience of a commercial control panel without licensing costs, and who are comfortable self-hosting on their own VPS or dedicated hardware. Its closest competitors are Pterodactyl itself (the project it forked from and still shares tooling and eggs with), Multicraft (an older commercial Minecraft-focused panel), Crafty Controller (a lighter Python-based Minecraft panel), and AMP, the Application Management Panel, a commercial cross-game alternative. Pelican differentiates from Pterodactyl mainly on release velocity and security responsiveness, and from commercial panels on cost, since it carries no licensing fee. Because it is infrastructure software rather than a hosted SaaS product, there is no subscription, no free-tier usage cap and no paid upgrade tier; users supply their own server hardware and the software itself is installed at no cost. Documentation, migration guides from Pterodactyl, and installer scripts are maintained by the community at pelican.dev and within the pelican-dev GitHub organization.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '55f67bf7-283b-46a3-a504-fefc5445313f';

