-- ── Penpot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Penpot is an open-source, web-based design and prototyping platform built by Kaleidos that lets designers and developers collaborate on UI design, design systems and interactive prototypes.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Madrid, Spain$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Penpot Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Penpot is an open-source Figma alternative for UI design and prototyping. Compare its free and paid plans, features and top competitors.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Penpot is an open-source design and prototyping platform built by Kaleidos, a Madrid, Spain-based technology company founded in 2011 by Pablo Ruiz Muzquiz and Enrique Posner that pivoted from a software consultancy into an open-source product company to build Penpot. The first alpha version launched on February 2, 2021 and was unveiled publicly at the FOSDEM open-source conference, positioning Penpot early on as an open-source alternative to proprietary, closed-source design tools like Figma, Sketch and Adobe XD. Penpot is released under the Mozilla Public License 2.0, works entirely in the browser, and can also be self-hosted on a company's own infrastructure, which appeals to organizations with strict data-residency or security requirements. By mid-2023 the platform had grown to over 400,000 users, and Kaleidos raised an $8 million Series A round in 2022, led by Decibel Partners, just two weeks after Adobe's high-profile $20 billion acquisition announcement for Figma, followed by a $12 million Series A+ extension in 2023 to fund continued development while preserving Penpot's open-source status. Kaleidos itself is a relatively small company, generally reported at around 11 to 50 employees, and operates with an employee-ownership structure in which staff hold a majority stake. Penpot's core differentiators are its fully open-source codebase, native SVG-based file format that keeps designs interoperable with standard web technologies, built-in design-to-code handoff, and a pricing model that keeps a genuinely usable free tier alongside paid cloud plans and self-hosted enterprise options, rather than gating core design functionality behind a paywall as many proprietary tools do. Its free Professional plan supports small teams (up to eight members) with unlimited design files and 10GB of storage, a paid Unlimited plan adds more storage and longer version history for around $7 per user per month with a monthly bill cap, and an Enterprise plan adds SSO, audit logs and centralized administration; organizations that want a fully private, self-hosted deployment can also purchase a Private Server plan. Penpot targets product design teams, developers who need accurate design-to-code handoff, and organizations, including government agencies and privacy-conscious companies, that prefer or require open-source, self-hostable software over proprietary cloud tools. Its closest competitors are Figma, the dominant proprietary collaborative design tool it was built to counter, along with Sketch, Adobe XD and, in the open-source category, tools like Penpot's own predecessors and lighter prototyping apps such as Pencil Project.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e79526e3-fc9f-4ec0-848a-0c70b7a3bd92';

