-- ── Percy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Percy is a visual review and visual regression testing platform, now owned by BrowserStack, that captures and compares UI screenshots across browsers to catch unintended visual changes in code.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (5,000 screenshots/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Part of BrowserStack (approximately 1,800 employees)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (now operated under BrowserStack)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Percy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Percy by BrowserStack is a visual regression testing tool for catching UI bugs. Compare its free and paid plans, features and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Percy is a visual review and visual regression testing platform originally built by Perceptual Inc., a startup founded in 2015 and based in San Francisco, California. Percy's core idea was to automate the tedious, error-prone process of manually checking whether a code change accidentally altered the visual appearance of a web application: it captures screenshots of an application's UI at defined checkpoints during automated test runs, compares them pixel-by-pixel (or using perceptual diffing) against an approved baseline, and flags visual differences for a human reviewer to approve or reject before code merges. In July 2020, Percy was acquired by BrowserStack, the large cross-browser and device testing platform, and Percy has since been integrated into BrowserStack's broader test infrastructure while continuing to operate under its own Percy branding and percy.io site. BrowserStack itself has grown into a company of roughly 1,800 employees with headquarters variously reported in Dublin, Ireland and Mumbai, India, giving Percy substantially more engineering and infrastructure resources than it had as a standalone startup. Percy's pricing follows a freemium, usage-based model measured in monthly screenshots: a free plan includes 5,000 screenshots per month with unlimited users and projects, a Professional plan (roughly $149 to $199 per month depending on annual or monthly billing) includes about 25,000 screenshots per month and a year of build history, and an Enterprise tier offers custom SLAs, SOC 2/ISO compliance documentation, dedicated support and unlimited device access at negotiated pricing. Percy integrates with popular CI/CD pipelines and testing frameworks such as Cypress, Playwright, Selenium and Storybook, and supports cross-browser and responsive visual testing across many browser and viewport combinations. It primarily targets frontend engineering teams, QA engineers and design systems teams at companies that ship UI changes frequently and want automated protection against visual regressions, rather than functional bugs alone. Percy's closest competitors include Chromatic (a visual testing tool built specifically around Storybook, from the maintainers of Storybook), Applitools (an AI-powered visual testing platform with its own Visual AI comparison engine), and BackstopJS (an open-source, self-hosted visual regression testing tool). Percy differentiates itself through deep integration with BrowserStack's broader real-device and cross-browser testing infrastructure, letting teams combine visual review with functional and cross-browser test coverage in one platform rather than stitching together separate tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0521ec36-4a18-4308-8b35-efe654ddfaa1';

