-- ── Perkbox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Perkbox is a UK-based employee benefits, rewards and recognition platform that gives businesses a single portal for perks, discounts, wellbeing support and peer-to-peer recognition.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Approximately 280 employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Perkbox Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Perkbox is a UK employee benefits and rewards platform offering perks, wellbeing and recognition. See features, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Perkbox is a London-headquartered employee benefits, rewards and recognition platform founded in 2010, originally launched under the name HuddleBuy before rebranding to Perkbox as it shifted focus toward workplace perks and engagement. The company employs roughly 280 people and has grown into one of the more recognizable employee benefits platforms in the UK market, now serving over 5,000 businesses across more than 30 countries with hundreds of thousands of employees logging into the platform regularly. Perkbox's core offering is a single portal that consolidates several categories of employee experience tools: a discounts and perks marketplace with access to more than 9,000 offers from well-known retail, leisure, wellness and lifestyle brands; wellbeing support including access to private and public medical or mental health resources; and recognition tools that let employers and peers award monetary or gift-based incentives for good performance. The platform is aimed at HR and people teams at small, mid-size and large employers who want to improve retention and engagement by bundling perks, benefits administration and recognition into one system rather than managing separate point solutions for discounts, wellness and rewards. Perkbox sells on a custom, per-employee subscription basis rather than publishing list pricing, with cost varying by company size, selected modules and contract length; some reviewers note that pricing can run higher than assembling comparable perks individually through separate providers, which is a common trade-off for platform consolidation and administrative convenience. Perkbox differentiates itself from single-purpose recognition or discount platforms by bundling perks, wellbeing and recognition together, and from larger global benefits platforms with a more UK- and Europe-centric perks catalog and small-to-mid-market focus, though it has expanded its international footprint over time. Its most direct competitors include Reward Gateway (a UK-founded employee engagement and benefits platform with similar scope), Benefex (an enterprise-focused UK benefits administration platform), and other recognition-focused tools; Perkbox is generally positioned as a mid-market-friendly alternative to heavier enterprise benefits administration suites, prioritizing a consumer-style discounts marketplace alongside HR-facing recognition and wellbeing tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '42ee2d70-9cde-4237-84bd-e916bc055119';

